class TestimonialPopup{constructor(){this.testimonials=[{name:"Sarah Jenkins",time:"2 days ago",text:"Just withdrew $5,000 to my crypto wallet. Fast as always!",avatar:"https://randomuser.me/api/portraits/women/44.jpg",company:"Tech Entrepreneur",location:"New York, USA",investedAmount:"$25,000",rating:5},{name:"Michael Ross",time:"5 hours ago",text:"The Gold plan ROI is insane. 30% in 24h actually works.",avatar:"https://randomuser.me/api/portraits/men/32.jpg",company:"Business Owner",location:"London, UK",investedAmount:"$50,000",rating:5},{name:"David Koch",time:"1 week ago",text:"Best platform for automated trading. Highly recommended.",avatar:"https://randomuser.me/api/portraits/men/85.jpg",company:"Retired Engineer",location:"Berlin, Germany",investedAmount:"$15,000",rating:5},{name:"Elena Volkov",time:"Just now",text:"Got my debit card today. Looks sleek and works perfectly.",avatar:"https://randomuser.me/api/portraits/women/65.jpg",company:"Marketing Director",location:"Moscow, Russia",investedAmount:"$30,000",rating:5},{name:"James Wright",time:"3 days ago",text:"Customer support helped me setup 2FA in minutes.",avatar:"https://randomuser.me/api/portraits/men/22.jpg",company:"Day Trader",location:"Toronto, Canada",investedAmount:"$75,000",rating:5},{name:"Robert Parker",time:"Yesterday",text:"I've been investing for 3 months. Consistent profits.",avatar:"https://randomuser.me/api/portraits/men/5.jpg",company:"Real Estate Investor",location:"Dubai, UAE",investedAmount:"$100,000",rating:5},{name:"Linda Meyer",time:"12 hours ago",text:"Finally a platform that pays on time. Five stars.",avatar:"https://randomuser.me/api/portraits/women/90.jpg",company:"Financial Advisor",location:"Sydney, Australia",investedAmount:"$40,000",rating:5},{name:"Ahmed Hassan",time:"4 hours ago",text:"Oil & energy investments portfolio is performing beyond expectations!",avatar:"https://randomuser.me/api/portraits/men/45.jpg",company:"Oil Industry Executive",location:"Abu Dhabi, UAE",investedAmount:"$150,000",rating:5},{name:"Priya Sharma",time:"6 hours ago",text:"Agricultural investments providing steady monthly returns. Love it!",avatar:"https://randomuser.me/api/portraits/women/33.jpg",company:"Healthcare Professional",location:"Mumbai, India",investedAmount:"$20,000",rating:5},{name:"Carlos Rodriguez",time:"1 day ago",text:"The referral program alone has earned me $12,000. Amazing!",avatar:"https://randomuser.me/api/portraits/men/67.jpg",company:"Sales Manager",location:"Mexico City, Mexico",investedAmount:"$35,000",rating:5}];this.baseInvestorCount=47500;this.dailyIncrement=Math.floor(Math.random()*50)+25;this.shownIndices=JSON.parse(localStorage.getItem('shownTestimonials')||'[]');this.popupElement=null;this.init();}
getInvestorCount(){const storedData=JSON.parse(localStorage.getItem('investorCountData')||'{}');const today=new Date().toDateString();if(storedData.date!==today){const newCount=(storedData.count||this.baseInvestorCount)+this.dailyIncrement;localStorage.setItem('investorCountData',JSON.stringify({date:today,count:newCount}));return newCount;}
return storedData.count||this.baseInvestorCount;}
init(){this.createPopupElement();setTimeout(()=>this.showRandomTestimonial(),5000);setInterval(()=>this.showRandomTestimonial(),30000);}
createPopupElement(){const div=document.createElement('div');div.id='testimonial-popup';div.setAttribute('role','alert');div.setAttribute('aria-live','polite');div.setAttribute('aria-label','New investor review notification');const isMobile=window.innerWidth<=768;div.style.cssText=`position:fixed;bottom:${isMobile?'70px':'20px'};left:${isMobile?'10px':'20px'};right:${isMobile?'10px':'auto'};background:linear-gradient(135deg,#0d1b2a 0%,#1b263b 100%);border-radius:12px;padding:${isMobile?'10px':'12px'};max-width:${isMobile?'calc(100% - 20px)':'300px'};box-shadow:0 8px 24px rgba(0,0,0,0.4),0 0 0 1px rgba(245,158,11,0.2);z-index:500;display:none;font-family:'Inter','Roboto',arial,sans-serif;transform:translateY(20px);opacity:0;transition:all 0.4s ease;border-left:3px solid#FFD700;`;document.body.appendChild(div);this.popupElement=div;}
showRandomTestimonial(){let available=this.testimonials.map((_,i)=>i).filter(i=>!this.shownIndices.includes(i));if(available.length===0){this.shownIndices=[];available=this.testimonials.map((_,i)=>i);}
const randomIndex=available[Math.floor(Math.random()*available.length)];const data=this.testimonials[randomIndex];const investorCount=this.getInvestorCount().toLocaleString();this.shownIndices.push(randomIndex);if(this.shownIndices.length>5)this.shownIndices.shift();localStorage.setItem('shownTestimonials',JSON.stringify(this.shownIndices));const stars='★'.repeat(data.rating)+'☆'.repeat(5-data.rating);const isMobile=window.innerWidth<=768;this.popupElement.innerHTML=`<div style="display: flex; gap: ${isMobile ? '8px' : '10px'}; align-items: flex-start;"><img src="${data.avatar}"
alt="${data.name}"
style="width: ${isMobile ? '36px' : '42px'}; height: ${isMobile ? '36px' : '42px'}; border-radius: 50%; object-fit: cover; border: 2px solid #FFD700; flex-shrink: 0;"
onerror="this.src='https://ui-avatars.com/api/?name=${encodeURIComponent(data.name)}&background=FFD700&color=000&size=42'"><div style="flex: 1; min-width: 0;"><div style="display: flex; justify-content: space-between; align-items: center;"><span style="font-weight: 600; color: #fff; font-size: ${isMobile ? '0.8rem' : '0.85rem'};">${data.name}</span><span style="color: #00A86B; font-size: 0.65rem;">✓ Verified</span></div><div style="font-size: 0.65rem; color: #94a3b8; margin: 2px 0;">📍 ${data.location}</div><div style="color: #fbbc04; font-size: 0.7rem; letter-spacing: 0;">${stars}</div><p style="color: #e2e8f0; font-size: ${isMobile ? '0.75rem' : '0.8rem'}; margin: 4px 0 0 0; line-height: 1.3;">"${data.text}"</p><div style="display: flex; justify-content: space-between; margin-top: 6px; font-size: 0.65rem;"><span style="color: #00A86B;">💰 ${data.investedAmount}</span><span style="color: #64748b;">👥 ${investorCount}+</span></div></div><button onclick="document.getElementById('testimonial-popup').style.display='none';"
style="background: transparent; border: none; color: #64748b; cursor: pointer; font-size: 0.9rem; padding: 0; width: 20px; height: 20px;"
aria-label="Close">×</button></div>`;this.popupElement.style.display='block';setTimeout(()=>{this.popupElement.style.opacity='1';this.popupElement.style.transform='translateY(0)';},10);setTimeout(()=>{this.popupElement.style.opacity='0';this.popupElement.style.transform='translateY(20px)';setTimeout(()=>{this.popupElement.style.display='none';},500);},8000);}}
document.addEventListener('DOMContentLoaded',()=>{new TestimonialPopup();});